import androidx.room.*
import kotlinx.coroutines.flow.Flow

@Entity(tableName = "note", indices = [Index("createdAt")])
data class NoteEntity(
  @PrimaryKey(autoGenerate = true) val id: Long = 0,
  val title: String,
  val body: String,
  val createdAt: Long
)

@Dao
interface NoteDao {
  @Query("SELECT * FROM note ORDER BY createdAt DESC")
  fun observeAll(): Flow<List<NoteEntity>>

  @Insert(onConflict = OnConflictStrategy.REPLACE)
  suspend fun upsert(note: NoteEntity): Long

  @Query("DELETE FROM note WHERE id = :id")
  suspend fun delete(id: Long)

  @Query("SELECT * FROM note WHERE title LIKE '%' || :q || '%'")
  suspend fun search(q: String): List<NoteEntity>
}

@Database(entities = [NoteEntity::class], version = 2, exportSchema = true)
abstract class AppDatabase : RoomDatabase() {
  abstract fun notes(): NoteDao
}

// Migration v1 → v2 — added `body` column
val MIGRATION_1_2 = object : Migration(1, 2) {
  override fun migrate(db: SupportSQLiteDatabase) {
    db.execSQL("ALTER TABLE note ADD COLUMN body TEXT NOT NULL DEFAULT ''")
  }
}

// Build
val db = Room.databaseBuilder(context, AppDatabase::class.java, "app.db")
  .addMigrations(MIGRATION_1_2)
  .fallbackToDestructiveMigrationOnDowngrade()
  .build()

// Use
class NoteRepo(private val dao: NoteDao) {
  fun observe() = dao.observeAll()
  suspend fun add(title: String) = dao.upsert(NoteEntity(title = title, body = "", createdAt = System.currentTimeMillis()))
}

import androidx.room.*
import java.util.Date
import kotlinx.serialization.json.Json
import kotlinx.serialization.encodeToString
import kotlinx.serialization.decodeFromString

enum class Priority { LOW, MEDIUM, HIGH }

class Converters {
  // Date <-> Long
  @TypeConverter fun fromDate(value: Date?): Long? = value?.time
  @TypeConverter fun toDate(value: Long?): Date? = value?.let { Date(it) }

  // Enum <-> String (Room can also do this with @ColumnInfo type, but explicit is fine)
  @TypeConverter fun fromPriority(p: Priority): String = p.name
  @TypeConverter fun toPriority(s: String): Priority = enumValueOf(s)

  // List<String> <-> JSON
  private val json = Json
  @TypeConverter fun fromTags(tags: List<String>): String = json.encodeToString(tags)
  @TypeConverter fun toTags(raw: String): List<String> = json.decodeFromString(raw)
}

@Entity(tableName = "task")
data class TaskEntity(
  @PrimaryKey val id: Long,
  val title: String,
  val due: Date?,
  val priority: Priority,
  val tags: List<String>
)

@Database(entities = [TaskEntity::class], version = 1)
@TypeConverters(Converters::class)
abstract class TaskDb : RoomDatabase()

