//   message UserSettings { string theme = 1; bool notifications = 2; }
// 2) Generate Java/Kotlin classes via Gradle plugin
// 3) Provide a Serializer<T>
import androidx.datastore.core.Serializer
import androidx.datastore.dataStore

object UserSettingsSerializer : Serializer<UserSettings> {
  override val defaultValue: UserSettings = UserSettings.getDefaultInstance()
  override suspend fun readFrom(input: InputStream) = UserSettings.parseFrom(input)
  override suspend fun writeTo(t: UserSettings, output: OutputStream) = t.writeTo(output)
}

val Context.user by dataStore(fileName = "user_settings.pb", serializer = UserSettingsSerializer)

