import androidx.work.*
import kotlinx.coroutines.flow.*

// 1) UI reads from Room — Flow always emits latest local state
class TodoRepo(private val dao: TodoDao, private val api: TodoApi) {
  fun observe(): Flow<List<Todo>> = dao.observeAll().map { it.map { e -> e.toDomain() } }

  suspend fun add(title: String) {
    val now = System.currentTimeMillis()
    val local = TodoEntity(id = randomId(), title = title, done = false, dirty = true, updatedAt = now)
    dao.upsert(local)                                         // optimistic local write
    OutboxScheduler.scheduleSync(context)                    // enqueue background sync
  }
}

// 2) Background sync worker
class SyncWorker(ctx: Context, params: WorkerParameters) : CoroutineWorker(ctx, params) {
  override suspend fun doWork(): Result {
    val pending = dao.getDirty()
    for (t in pending) {
      try {
        api.upsert(t.toDto())
        dao.markClean(t.id)
      } catch (e: IOException) {
        return Result.retry()                                 // WM applies backoff
      }
    }
    val server = api.fetchAll()
    dao.replaceAllRemote(server.map { it.toEntity() })       // pull merge
    return Result.success()
  }
}

// 3) Schedule
object OutboxScheduler {
  fun scheduleSync(ctx: Context) {
    val req = OneTimeWorkRequestBuilder<SyncWorker>()
      .setConstraints(Constraints(requiredNetworkType = NetworkType.CONNECTED))
      .setBackoffCriteria(BackoffPolicy.EXPONENTIAL, 30, TimeUnit.SECONDS)
      .build()
    WorkManager.getInstance(ctx).enqueueUniqueWork("sync_todos", ExistingWorkPolicy.APPEND, req)
  }
}
